        boolean forceTransparentWhite = false;

        if (hints.containsKey(PNGTranscoder.KEY_FORCE_TRANSPARENT_WHITE)) {
            forceTransparentWhite =
                    (Boolean) hints.get
                            (PNGTranscoder.KEY_FORCE_TRANSPARENT_WHITE);
